const item = $input.first().json;

// Try to find the text wherever it lives
let raw;
if (item?.content?.parts?.[0]?.text) {
  raw = item.content.parts[0].text;
} else if (item?.parts?.[0]?.text) {
  raw = item.parts[0].text;
} else if (typeof item === "string") {
  raw = item;
} else {
  // Fallback: dump the whole structure so we can see it
  return [{ json: { error: "structure_not_found", debug: item } }];
}

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = { error: "parse_failed", raw_text: raw };
}

return [{ json: parsed }];

const item = $input.first().json;

// item currently holds the JD fields from the previous Code node
const jdData = {
  company: item.company,
  role_title: item.role_title,
  jd_text_clean: item.jd_text_clean,
  required_skills: item.required_skills,
  nice_to_have_skills: item.nice_to_have_skills
};

// Read and parse the master resume binary
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const jsonString = buffer.toString('utf-8');
const masterResume = JSON.parse(jsonString);

// Combine both into one object going forward
return [{
  json: {
    jd: jdData,
    resume: masterResume
  }
}];

